import axios from 'axios';

class BiwengerClient {
    constructor(token = null, userId = null, leagueId = null) {
        const isWeb = typeof window !== 'undefined';
        const proxy = (isWeb && window.location.hostname === 'localhost') ? "https://cors-anywhere.herokuapp.com/" : "";

        this.baseUrl = `${proxy}https://biwenger.as.com/api/v2`;
        this.token = token;
        this.userId = userId;
        this.leagueId = leagueId;
        this.headers = {
            "Content-Type": "application/json",
            "Accept": "application/json, text/plain, */*",
            "X-Version": "566",
            "X-Lang": "es"
        };
        if (this.token) {
            this.headers["Authorization"] = `Bearer ${this.token}`;
        }
        if (this.userId) this.headers["X-User"] = String(this.userId);
        if (this.leagueId) this.headers["X-League"] = String(this.leagueId);
    }

    async login(email, password) {
        try {
            console.log("Attempting login for:", email);
            const res = await axios.post(`${this.baseUrl}/auth/login`, { email, password }, { headers: this.headers });
            const data = res.data;
            console.log("Login raw response data:", data);

            this.token = data.token || data.data?.token;
            if (!this.token) {
                console.error("Token not found in response");
                return null;
            }

            // CRITICAL: Manually set the auth header for the next call
            const authHeaders = { 
                ...this.headers, 
                "Authorization": `Bearer ${this.token}` 
            };

            const accRes = await axios.get(`${this.baseUrl}/account`, { headers: authHeaders });
            const accData = accRes.data.data || {};

            this.headers["Authorization"] = `Bearer ${this.token}`;
            let userId = accData.id;
            const leagues = accData.leagues || [];
            if (leagues.length > 0) {
                this.leagueId = String(leagues[0].id);
                this.headers["X-League"] = this.leagueId;
                if (!userId) userId = leagues[0].user?.id;
            }
            if (userId) {
                this.userId = String(userId);
                this.headers["X-User"] = this.userId;
            }

            return {
                token: this.token,
                user_id: this.userId,
                league_id: this.leagueId
            };
        } catch (error) {
            if (error.response) {
                console.error("Login failed with status:", error.response.status);
                console.error("Error data:", error.response.data);
            } else {
                console.error("Login failed:", error.message);
            }
            return null;
        }
    }

    async getPlayerData() {
        try {
            const fields = "*,players(*,fitness,team,owner),nextRounds(*),team(*),league(*,points,customState,board,rules,market,activeOffers,userDraft)";
            const res = await axios.get(`${this.baseUrl}/user?fields=${fields}`, { headers: this.headers });
            const userData = res.data.data || {};
            const userPlayerIds = new Set((userData.players || []).map(p => p.id));
            const compSlug = userData.league?.competition || "la-liga";

            const compRes = await axios.get(`https://cf.biwenger.com/api/v2/competitions/${compSlug}/data?score=2`, { headers: { "User-Agent": this.headers["User-Agent"] } });
            const compData = compRes.data.data || {};
            const allPlayers = compData.players || {};
            const allTeams = compData.teams || {};

            const teamNames = {};
            const teamRivals = {};
            Object.entries(allTeams).forEach(([id, t]) => {
                teamNames[id] = t.name;
                const nextGames = t.nextGames || [];
                if (nextGames.length > 0) {
                    const game = nextGames[0];
                    const homeId = game.home?.id;
                    const awayId = game.away?.id;
                    const isHome = String(homeId) === String(id);
                    const rivalId = isHome ? awayId : homeId;
                    teamRivals[id] = {
                        rival: allTeams[rivalId]?.name || `Team ${rivalId}`,
                        location: isHome ? "Home" : "Away",
                        date: game.date || 0
                    };
                }
            });

            const playerList = [];
            Object.entries(allPlayers).forEach(([id, p]) => {
                if (userPlayerIds.has(Number(id))) {
                    const positions = [p.position, ...(p.altPositions || [])];
                    const matchInfo = teamRivals[p.teamID || p.team] || { rival: "Unknown", location: "Unknown", date: 0 };

                    playerList.push({
                        id: Number(id),
                        name: p.name,
                        position: p.position,
                        positions: [...new Set(positions)],
                        status: p.status,
                        fitness: p.fitness || [],
                        team_id: p.teamID || p.team,
                        team_name: teamNames[p.teamID || p.team] || "Unknown",
                        rival_name: matchInfo.rival,
                        location: matchInfo.location,
                        match_date: matchInfo.date,
                        price_trend: p.priceIncrement || 0
                    });
                }
            });

            return playerList;
        } catch (error) {
            console.error("Failed to fetch player data", error);
            return [];
        }
    }
}

export default BiwengerClient;
